import React from 'react'
import Star from './Star'
import useState from 'react'

function StarRate() {
  return (
    <div>
    {[... new Array(5)].map((star, index)=>{
        return <a href="#" onClick={(e) =>{
            e.preventDefault()
            setRate(index+1)
            }}>
        <Star position={index}/>
        </a>
    })}
   </div>
  )
}

export default StarRate
